import{_ as o,C as i,o as t,c as n,a2 as l,b as r,w as s,a as d,E as c,a3 as p,j as h}from"./chunks/framework.B72_uj9U.js";const x=JSON.parse('{"title":"Pi — Tool System","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/pi-coding-agent/tool-system.md","filePath":"research/agents/pi-coding-agent/tool-system.md"}'),m={name:"research/agents/pi-coding-agent/tool-system.md"};function u(g,e,b,f,y,k){const a=i("Mermaid");return t(),n("div",null,[e[1]||(e[1]=l(`<h1 id="pi-—-tool-system" tabindex="-1">Pi — Tool System <a class="header-anchor" href="#pi-—-tool-system" aria-label="Permalink to &quot;Pi — Tool System&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Pi&#39;s tool system embodies its &quot;primitives not features&quot; philosophy. The coding agent ships with exactly four tools: <code>read</code>, <code>write</code>, <code>edit</code>, and <code>bash</code>. Every other capability — web access, MCP integration, sub-agents, code search, Git operations — is added through three extensibility mechanisms: extensions (TypeScript), skills (SKILL.md), and packages (distribution bundles).</p><p>This minimal default tool set keeps the system prompt small, the prompt cache stable, and the agent&#39;s behavior predictable. Extensions can add arbitrarily complex tools, but the core never grows.</p><h2 id="the-four-default-tools" tabindex="-1">The Four Default Tools <a class="header-anchor" href="#the-four-default-tools" aria-label="Permalink to &quot;The Four Default Tools&quot;">​</a></h2><h3 id="_1-read-—-file-reading" tabindex="-1">1. <code>read</code> — File Reading <a class="header-anchor" href="#_1-read-—-file-reading" aria-label="Permalink to &quot;1. \`read\` — File Reading&quot;">​</a></h3><p>Reads file contents and returns them to the LLM. This is the agent&#39;s primary way of understanding existing code.</p><p><strong>Characteristics:</strong></p><ul><li>Reads single files or specific line ranges</li><li>Returns content with line numbers for precise reference</li><li>The simplest of the four tools — no side effects</li></ul><h3 id="_2-write-—-file-writing" tabindex="-1">2. <code>write</code> — File Writing <a class="header-anchor" href="#_2-write-—-file-writing" aria-label="Permalink to &quot;2. \`write\` — File Writing&quot;">​</a></h3><p>Creates new files or completely overwrites existing files with new content.</p><p><strong>Characteristics:</strong></p><ul><li>Full-file replacement semantics</li><li>Creates parent directories as needed</li><li>Used for new file creation and complete rewrites</li><li>For surgical edits, the <code>edit</code> tool is preferred</li></ul><h3 id="_3-edit-—-surgical-file-editing" tabindex="-1">3. <code>edit</code> — Surgical File Editing <a class="header-anchor" href="#_3-edit-—-surgical-file-editing" aria-label="Permalink to &quot;3. \`edit\` — Surgical File Editing&quot;">​</a></h3><p>Applies targeted edits to existing files using search-and-replace semantics.</p><p><strong>Characteristics:</strong></p><ul><li>Specifies old content to find and new content to replace it with</li><li>More token-efficient than <code>write</code> for small changes to large files</li><li>Requires exact string matching for the content to be replaced</li><li>Can fail if the search string doesn&#39;t match (stale context)</li></ul><h3 id="_4-bash-—-shell-command-execution" tabindex="-1">4. <code>bash</code> — Shell Command Execution <a class="header-anchor" href="#_4-bash-—-shell-command-execution" aria-label="Permalink to &quot;4. \`bash\` — Shell Command Execution&quot;">​</a></h3><p>Executes shell commands and returns their output (stdout and stderr).</p><p><strong>Characteristics:</strong></p><ul><li>Full shell access — any command the environment supports</li><li>No built-in sandboxing or permission gates (by design)</li><li>No background execution support (use tmux for that)</li><li>Extensions can add permission gates, command filtering, or sandboxing</li></ul><p><strong>Why only these four?</strong> These are the primitive operations for coding: read code, write code, edit code, run commands. Every higher-level operation (search, test, lint, deploy, git) can be composed from these primitives via <code>bash</code>. Adding more built-in tools would mean more system prompt tokens, more prompt cache variability, and more opinions baked into the core.</p><h2 id="the-extension-api-for-custom-tools" tabindex="-1">The Extension API for Custom Tools <a class="header-anchor" href="#the-extension-api-for-custom-tools" aria-label="Permalink to &quot;The Extension API for Custom Tools&quot;">​</a></h2><p>Extensions are TypeScript modules that can register new tools with full schema definitions, handlers, and UI integration.</p><h3 id="registering-a-custom-tool" tabindex="-1">Registering a Custom Tool <a class="header-anchor" href="#registering-a-custom-tool" aria-label="Permalink to &quot;Registering a Custom Tool&quot;">​</a></h3><p>Extensions use the Pi extension API to define tools with:</p><ul><li><strong>Name</strong>: The tool identifier the LLM calls</li><li><strong>Description</strong>: What the tool does (injected into the system prompt)</li><li><strong>Schema</strong>: JSON Schema for tool parameters</li><li><strong>Handler</strong>: TypeScript function that executes the tool call</li><li><strong>Validation</strong>: Optional parameter validation before execution</li></ul><h3 id="what-extensions-can-do" tabindex="-1">What Extensions Can Do <a class="header-anchor" href="#what-extensions-can-do" aria-label="Permalink to &quot;What Extensions Can Do&quot;">​</a></h3><p>Extensions have broad capabilities beyond just tool registration:</p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td><strong>Register tools</strong></td><td>Add new tools or replace built-in tools entirely</td></tr><tr><td><strong>Register commands</strong></td><td>Add slash commands (e.g., <code>/deploy</code>, <code>/review</code>)</td></tr><tr><td><strong>Keyboard shortcuts</strong></td><td>Bind actions to key combinations</td></tr><tr><td><strong>Event handlers</strong></td><td>Subscribe to agent lifecycle events</td></tr><tr><td><strong>UI components</strong></td><td>Custom status lines, headers, footers, editors</td></tr><tr><td><strong>Context injection</strong></td><td>Add messages to conversation, filter history</td></tr><tr><td><strong>Sub-agents</strong></td><td>Spawn and coordinate multiple pi instances</td></tr><tr><td><strong>Plan mode</strong></td><td>Implement planning workflows</td></tr><tr><td><strong>Permission gates</strong></td><td>Add approval prompts before tool execution</td></tr><tr><td><strong>Path protection</strong></td><td>Prevent modifications to specific files/directories</td></tr><tr><td><strong>Git checkpointing</strong></td><td>Auto-commit before/after tool calls</td></tr><tr><td><strong>SSH execution</strong></td><td>Run tools on remote machines</td></tr><tr><td><strong>MCP integration</strong></td><td>Connect to MCP servers</td></tr><tr><td><strong>Games</strong></td><td>Yes, someone got Doom running in pi</td></tr></tbody></table><h3 id="tool-replacement" tabindex="-1">Tool Replacement <a class="header-anchor" href="#tool-replacement" aria-label="Permalink to &quot;Tool Replacement&quot;">​</a></h3><p>A unique capability: extensions can replace the built-in tools entirely. If you want <code>edit</code> to behave differently — perhaps using a diff-based approach instead of search-and-replace — you can register a tool with the same name and your handler takes over. The original tool is fully replaced, not wrapped.</p><p>This means Pi&#39;s &quot;four default tools&quot; are really &quot;four default tools that you can swap out.&quot; The defaults are sensible for most users, but power users can customize everything.</p><h2 id="the-skills-system" tabindex="-1">The Skills System <a class="header-anchor" href="#the-skills-system" aria-label="Permalink to &quot;The Skills System&quot;">​</a></h2><p>Skills are a lighter-weight extensibility mechanism designed for progressive context disclosure. Where extensions are TypeScript code that hooks into the agent runtime, skills are Markdown files that describe capabilities.</p><h3 id="skill-md-format" tabindex="-1">SKILL.md Format <a class="header-anchor" href="#skill-md-format" aria-label="Permalink to &quot;SKILL.md Format&quot;">​</a></h3><p>A skill is a SKILL.md file placed in <code>~/.pi/agent/skills/</code> or in a project directory:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;"># Skill: Database Migration</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Description</span></span>
<span class="line"><span style="color:#CDD6F4;">This skill helps manage database migrations using the project&#39;s migration framework.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Tools</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Run </span><span style="color:#A6E3A1;">\`npm run migrate:create &lt;name&gt;\`</span><span style="color:#CDD6F4;"> to create a new migration</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Run </span><span style="color:#A6E3A1;">\`npm run migrate:up\`</span><span style="color:#CDD6F4;"> to apply pending migrations</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Run </span><span style="color:#A6E3A1;">\`npm run migrate:down\`</span><span style="color:#CDD6F4;"> to rollback the last migration</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Conventions</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Migration files go in </span><span style="color:#A6E3A1;">\`src/migrations/\`</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Use snake_case for migration names</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Always create both up and down migrations</span></span></code></pre></div><h3 id="how-skills-work" tabindex="-1">How Skills Work <a class="header-anchor" href="#how-skills-work" aria-label="Permalink to &quot;How Skills Work&quot;">​</a></h3><ol><li><strong>Discovery</strong>: Skills are discovered from <code>~/.pi/agent/skills/</code>, project directories, and installed packages</li><li><strong>On-demand loading</strong>: Skills are NOT loaded into the system prompt by default. They&#39;re loaded when: <ul><li>The user invokes <code>/skill:name</code></li><li>The agent determines a skill is relevant (auto-loading)</li></ul></li><li><strong>Progressive disclosure</strong>: The skill content is injected into the conversation only when needed, preserving prompt cache for the common case</li><li><strong>Agent Skills standard</strong>: Pi skills follow the agentskills.io specification, making them portable across compatible agent implementations</li></ol><h3 id="skills-vs-extensions" tabindex="-1">Skills vs Extensions <a class="header-anchor" href="#skills-vs-extensions" aria-label="Permalink to &quot;Skills vs Extensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Skills</th><th>Extensions</th></tr></thead><tbody><tr><td>Format</td><td>Markdown (SKILL.md)</td><td>TypeScript</td></tr><tr><td>Complexity</td><td>Simple — instructions and conventions</td><td>Full — code execution, UI, events</td></tr><tr><td>Loading</td><td>On-demand, injected into context</td><td>Always active once installed</td></tr><tr><td>Capabilities</td><td>Describe how to use existing tools</td><td>Register new tools, modify behavior</td></tr><tr><td>Prompt impact</td><td>Only when activated</td><td>Always present in system prompt</td></tr><tr><td>Use case</td><td>Domain knowledge, project conventions</td><td>New capabilities, workflow changes</td></tr></tbody></table><h2 id="the-deliberate-absence-of-mcp" tabindex="-1">The Deliberate Absence of MCP <a class="header-anchor" href="#the-deliberate-absence-of-mcp" aria-label="Permalink to &quot;The Deliberate Absence of MCP&quot;">​</a></h2><p>Pi does not include Model Context Protocol (MCP) support in its core. This is a conscious and well-reasoned decision:</p><p><strong>Why no built-in MCP:</strong></p><ol><li><strong>Skills + bash cover most cases</strong>: A skill can describe how to use a CLI tool, and <code>bash</code> can execute it. This covers the same ground as most MCP servers without the protocol overhead.</li><li><strong>Prompt cache stability</strong>: MCP server tool definitions would be injected into the system prompt, varying based on which servers are connected. This breaks prompt cache.</li><li><strong>Complexity budget</strong>: MCP adds connection management, server lifecycle, protocol handling — all things that would complicate the core.</li><li><strong>Extension escape hatch</strong>: The community has built <code>pi-mcp-adapter</code> as a package that adds MCP support for users who need it.</li></ol><p><strong>The philosophy</strong>: Rather than building MCP into the core (where it would affect all users), Pi lets users who need MCP install a package. Users who don&#39;t need it never pay the complexity cost.</p><h2 id="pi-packages" tabindex="-1">Pi Packages <a class="header-anchor" href="#pi-packages" aria-label="Permalink to &quot;Pi Packages&quot;">​</a></h2><p>Packages are the distribution format for Pi extensions, skills, and other resources:</p><h3 id="what-a-package-contains" tabindex="-1">What a Package Contains <a class="header-anchor" href="#what-a-package-contains" aria-label="Permalink to &quot;What a Package Contains&quot;">​</a></h3><p>A package can bundle any combination of:</p><ul><li>Extensions (TypeScript modules)</li><li>Skills (SKILL.md files)</li><li>Prompt templates (reusable Markdown prompts)</li><li>Themes (TUI customization)</li></ul><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># From npm</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pi</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> npm:@foo/pi-tools</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># From git</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pi</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> git:github.com/user/repo</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># From local path</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pi</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> ./my-extension</span></span></code></pre></div><h3 id="discovery" tabindex="-1">Discovery <a class="header-anchor" href="#discovery" aria-label="Permalink to &quot;Discovery&quot;">​</a></h3><p>Packages are discoverable via:</p><ul><li>npm keyword <code>pi-package</code></li><li>The awesome-pi-agent curated list</li><li>Pi Discord community</li></ul><h3 id="notable-community-packages" tabindex="-1">Notable Community Packages <a class="header-anchor" href="#notable-community-packages" aria-label="Permalink to &quot;Notable Community Packages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Package</th><th>Description</th></tr></thead><tbody><tr><td>pi-skills</td><td>Collection of common skills for various frameworks</td></tr><tr><td>pi-messenger</td><td>Messaging integrations</td></tr><tr><td>pi-mcp-adapter</td><td>MCP protocol support</td></tr><tr><td>pi-web-access</td><td>Web browsing capabilities</td></tr></tbody></table><h2 id="tool-system-architecture-summary" tabindex="-1">Tool System Architecture Summary <a class="header-anchor" href="#tool-system-architecture-summary" aria-label="Permalink to &quot;Tool System Architecture Summary&quot;">​</a></h2>`,60)),(t(),r(p,null,{default:s(()=>[c(a,{id:"mermaid-600",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%2FLLM%20requests%20tool%20X%22%5D%20--%3E%20B%7B%22Extension%20tool%3Cbr%2F%3Eregistered%20for%20X%3F%22%7D%0A%20%20%20%20B%20--%20%22yes%22%20--%3E%20C%5B%22Extension%20Handler%3Cbr%2F%3E(includes%20replacements%20for%20built-in%20tools)%22%5D%0A%20%20%20%20B%20--%20%22not%20found%22%20--%3E%20D%5B%22Default%20Tools%3Cbr%2F%3Eread%20%7C%20write%20%7C%20edit%20%7C%20bash%22%5D%0A%20%20%20%20E%5B%22Skills%20inject%20instructions%22%5D%20--%3E%20F%5B%22Agent%20uses%20existing%20tools%22%5D%0A%20%20%20%20G%5B%22Packages%20bundle%20extensions%20%2B%20skills%3Cbr%2F%3Efor%20distribution%22%5D%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=h("p",null,"The tool system's elegance is in its layering: four primitive tools provide the foundation, extensions add arbitrary capabilities, skills describe how to use them, and packages distribute them. The core never needs to grow.",-1))])}const v=o(m,[["render",u]]);export{x as __pageData,v as default};
